/*Table structure for table `stu_course` */

DROP TABLE IF EXISTS `stu_course`;

CREATE TABLE `stu_course` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `student_id` int NOT NULL COMMENT '学生ID（对应学号/用户ID）',
  `term` varchar(20) NOT NULL COMMENT '学期标识（示例：2025-2026-1）',
  `name` varchar(100) NOT NULL COMMENT '课程名称',
  `teacher` varchar(50) DEFAULT NULL COMMENT '任课教师',
  `day_of_week` int NOT NULL COMMENT '星期几（1=周一…7=周日）',
  `start_section` int NOT NULL COMMENT '开始节次（从1开始）',
  `end_section` int NOT NULL COMMENT '结束节次（>=开始节次）',
  `location` varchar(100) DEFAULT NULL COMMENT '上课地点（教学楼/教室）',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注（如：专业核心/专业基础/方向课）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_course_student_term` (`student_id`,`term`),
  KEY `idx_course_weekview` (`student_id`,`term`,`day_of_week`,`start_section`),
  CONSTRAINT `ck_course_day` CHECK ((`day_of_week` between 1 and 7)),
  CONSTRAINT `ck_course_section` CHECK (((`start_section` >= 1) and (`end_section` >= `start_section`)))
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='学生课表';

