/*Table structure for table `stu_note` */

DROP TABLE IF EXISTS `stu_note`;

CREATE TABLE `stu_note` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `student_id` int NOT NULL COMMENT '学生ID（对应学号/用户ID）',
  `course_id` int DEFAULT NULL COMMENT '关联课程ID（可选，对应 stu_course.id）',
  `course_name_snapshot` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '课程名称快照（可选；课程被改名/删除后仍可显示）',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '笔记标题',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '笔记内容（纯文本/Markdown均可存）',
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '标签（逗号分隔，如：需求,设计,复习）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `cover_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '笔记封面',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_note_student` (`student_id`) USING BTREE,
  KEY `idx_note_student_course` (`student_id`,`course_id`) USING BTREE,
  KEY `idx_note_student_time` (`student_id`,`updated_at`) USING BTREE,
  KEY `fk_note_course` (`course_id`) USING BTREE,
  FULLTEXT KEY `ft_note_search` (`title`,`content`,`tags`),
  CONSTRAINT `fk_note_course` FOREIGN KEY (`course_id`) REFERENCES `stu_course` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='学习笔记';

