insert  into `stu_note`(`id`,`student_id`,`course_id`,`course_name_snapshot`,`title`,`content`,`tags`,`created_at`,`updated_at`,`cover_image`) values (1,10001,1,'软件工程导论','第1章：软件工程概述','软件工程的目标：在质量、成本、进度之间取得平衡。\n核心：过程、方法、工具。','概念,导论,复习','2026-05-09 08:55:32','2026-05-09 08:55:32',NULL),(2,10001,4,'数据库系统原理','SQL：DML 与 DDL 对比','DDL：CREATE/ALTER/DROP\nDML：SELECT/INSERT/UPDATE/DELETE\n注意事务与约束的影响。','数据库,SQL,总结','2026-05-09 08:55:32','2026-05-09 08:55:32',NULL),(3,10001,3,'数据结构与算法','链表与数组的差异','数组：随机访问快，插入删除慢。\n链表：插入删除快，随机访问慢。','数据结构,链表,数组','2026-05-09 08:55:32','2026-05-09 08:55:32',NULL),(4,10001,2,'面向对象程序设计(Java)','封装/继承/多态要点','封装：隐藏实现细节。\n继承：复用与扩展。\n多态：面向接口编程，运行期绑定。','Java,OOP,重点','2026-05-09 08:55:32','2026-05-09 08:55:32',NULL),(5,10001,NULL,NULL,'本周学习计划','1) 完成课表周视图联调\n2) 整理需求工程笔记\n3) 复习SQL与索引','计划,待办,复盘','2026-05-09 08:55:32','2026-05-09 08:55:32',NULL),(6,1001,1,'Java','1','<p># 实验名称：</p><p>啊啊</p><p><br></p><p>## 实验目的</p><p><br></p><p>- 啊啊</p><p><br></p><p><br></p><p>## 实验环境</p><p>啊啊</p><p>- OS：</p><p><br></p><p>- 语言/框架：</p><p>啊啊</p><p>- 依赖版本：</p><p><br></p><p>啊啊</p><p>## 实验步骤</p><p>啊啊</p><p>1. </p><p>啊啊</p><p>2. </p><p><br></p><p><br></p><p>## 关键代码/命令</p><p><br></p><p>```text</p><p>啊啊</p><p><br></p><p>```</p><p><br></p><p><br></p><p>## 结果与截图</p><p><br></p><p>- </p><p>啊啊</p><p><br></p><p>## 问题与解决</p><p><br></p><p>- 啊啊</p><p><br></p><p><br></p><p>## 总结</p><p>啊啊</p><p>- </p><p><br></p>','啊啊','2026-05-09 10:32:49','2026-05-09 10:32:49','/profile/upload/2026/05/09/3-1_20260509103216A001.jpg');

/*Table structure for table `stu_note_template` */

DROP TABLE IF EXISTS `stu_note_template`;

CREATE TABLE `stu_note_template` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `student_id` int DEFAULT NULL COMMENT '学生ID（为空表示系统内置模板；不为空表示学生自定义模板）',
  `name` varchar(50) NOT NULL COMMENT '模板名称',
  `type` varchar(20) NOT NULL COMMENT '模板类型（CLASS/EXPERIMENT/INTERVIEW/CUSTOM）',
  `content` longtext NOT NULL COMMENT '模板内容（纯文本/Markdown）',
  `sort_no` int NOT NULL DEFAULT '0' COMMENT '排序号（越小越靠前）',
  `status` char(1) NOT NULL DEFAULT '0' COMMENT '状态（0启用 1停用）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_template_student` (`student_id`),
  KEY `idx_template_type` (`type`),
  KEY `idx_template_status_sort` (`status`,`sort_no`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='笔记模板表';

